### React Component with useActionState Hook (Source)

Source: https://github.com/facebook/react/blob/main/compiler/packages/babel-plugin-react-compiler/src/__tests__/fixtures/compiler/useActionState-dispatch-considered-as-non-reactive.expect.md

Defines a React functional component `Component` that uses the `useActionState` hook. It sets up an `onSubmitAction` to dispatch an action and renders a `Foo` component, illustrating the hook's basic usage.

```javascript
import {useActionState} from 'react';

function Component() {
  const [actionState, dispatchAction] = useActionState();
  const onSubmitAction = () => {
    dispatchAction();
  };
  return <Foo onSubmitAction={onSubmitAction} />;
}

function Foo() {}

export const FIXTURE_ENTRYPOINT = {
  fn: Component,
  params: [],
};

```

--------------------------------

### Managing Form State and Optimistic Updates with useActionState

Source: https://context7.com/facebook/react/llms.txt

This example demonstrates the `useActionState` hook in React for managing form submissions and their state. It includes a sign-up form with client-side validation and a product card showing optimistic updates for adding items to a cart.

```jsx
import React, { useActionState } from 'react';

// Simulated server action
async function submitForm(previousState, formData) {
  const email = formData.get('email');
  const password = formData.get('password');

  // Simulate API call
  await new Promise(resolve => setTimeout(resolve, 1000));

  if (!email || !password) {
    return {
      success: false,
      error: 'Please fill in all fields',
      data: null
    };
  }

  if (password.length < 8) {
    return {
      success: false,
      error: 'Password must be at least 8 characters',
      data: null
    };
  }

  // Simulate successful submission
  return {
    success: true,
    error: null,
    data: { email, message: 'Account created successfully!' }
  };
}

function SignupForm() {
  const [state, formAction, isPending] = useActionState(submitForm, {
    success: false,
    error: null,
    data: null
  });

  return (
    <form action={formAction}>
      <h2>Sign Up</h2>

      {state.error && (
        <div className="error-message" role="alert">
          {state.error}
        </div>
      )}

      {state.success && (
        <div className="success-message" role="status">
          {state.data.message}
        </div>
      )}

      <div>
        <label htmlFor="email">Email:</label>
        <input
          type="email"
          id="email"
          name="email"
          required
          disabled={isPending}
        />
      </div>

      <div>
        <label htmlFor="password">Password:</label>
        <input
          type="password"
          id="password"
          name="password"
          required
          disabled={isPending}
        />
      </div>

      <button type="submit" disabled={isPending}>
        {isPending ? 'Creating account...' : 'Sign Up'}
      </button>
    </form>
  );
}

// Shopping cart example with optimistic updates
async function addToCart(previousState, formData) {
  const productId = formData.get('productId');
  const quantity = parseInt(formData.get('quantity') || '1');

  await new Promise(resolve => setTimeout(resolve, 500));

  // Simulate occasional failure
  if (Math.random() < 0.1) {
    return {
      ...previousState,
      error: 'Failed to add item. Please try again.'
    };
  }

  return {
    items: [...previousState.items, { productId, quantity, addedAt: Date.now() }],
    error: null
  };
}

function ProductCard({ product }) {
  const [cartState, addAction, isPending] = useActionState(addToCart, {
    items: [],
    error: null
  });

  return (
    <div className="product-card">
      <h3>{product.name}</h3>
      <p>${product.price}</p>

      <form action={addAction}>
        <input type="hidden" name="productId" value={product.id} />
        <input type="number" name="quantity" defaultValue="1" min="1" />

        <button type="submit" disabled={isPending}>
          {isPending ? 'Adding...' : 'Add to Cart'}
        </button>
      </form>

      {cartState.error && <p className="error">{cartState.error}</p>}
    </div>
  );
}
```

