### Reading resources with the use hook in React

Source: https://context7.com/facebook/react/llms.txt

The use hook reads values from Promises or Context and is unique because it can be called conditionally. Components using use with a Promise will suspend until the Promise resolves.

```jsx
import React, { Suspense, use, cache } from 'react';

// Cached fetch function
const fetchUser = cache(async (userId) => {
  const response = await fetch(`/api/users/${userId}`);
  if (!response.ok) throw new Error('Failed to fetch user');
  return response.json();
});

const fetchPosts = cache(async (userId) => {
  const response = await fetch(`/api/users/${userId}/posts`);
  if (!response.ok) throw new Error('Failed to fetch posts');
  return response.json();
});

// Component that uses promises directly
function UserProfile({ userId }) {
  // use() can read promises - component suspends until resolved
  const user = use(fetchUser(userId));

  return (
    <div className="user-profile">
      <h2>{user.name}</h2>
      <p>{user.email}</p>
      <p>Member since: {new Date(user.createdAt).toLocaleDateString()}</p>
    </div>
  );
}

function UserPosts({ userId, showPosts }) {
  // use() can be called conditionally (unlike other hooks)
  if (!showPosts) {
    return <p>Posts hidden</p>;
  }

  const posts = use(fetchPosts(userId));

  return (
    <div className="user-posts">
      <h3>Posts ({posts.length})</h3>
      {posts.map(post => (
        <article key={post.id}>
          <h4>{post.title}</h4>
          <p>{post.excerpt}</p>
        </article>
      ))}
    </div>
  );
}

// use() with context - can be called conditionally
const ThemeContext = React.createContext('light');

function ConditionalThemedComponent({ useTheme }) {
  // Conditional context reading
  const theme = useTheme ? use(ThemeContext) : 'light';

  return (
    <div className={`themed-${theme}`}>
      Theme: {theme}
    </div>
  );
}

// Parent component with Suspense boundaries
function App() {
  const userId = 1;
  const [showPosts, setShowPosts] = React.useState(false);

  return (
    <ThemeContext.Provider value="dark">
      <div>
        <Suspense fallback={<div>Loading user...</div>}>
          <UserProfile userId={userId} />
        </Suspense>

        <button onClick={() => setShowPosts(!showPosts)}>
          {showPosts ? 'Hide' : 'Show'} Posts
        </button>

        <Suspense fallback={<div>Loading posts...</div>}>
          <UserPosts userId={userId} showPosts={showPosts} />
        </Suspense>

        <ConditionalThemedComponent useTheme={true} />
      </div>
    </ThemeContext.Provider>
  );
}
```

