### Implementing Optimistic UI with useOptimistic in React

Source: https://context7.com/facebook/react/llms.txt

Use this hook to provide immediate feedback for user actions like liking a post or adding items to a list. The optimistic state automatically reverts if the underlying async operation fails.

```jsx
import React, { useState, useOptimistic } from 'react';

// Like button with optimistic update
function LikeButton({ postId, initialLikes, initialLiked }) {
  const [likes, setLikes] = useState(initialLikes);
  const [isLiked, setIsLiked] = useState(initialLiked);

  const [optimisticLikes, setOptimisticLikes] = useOptimistic(
    { count: likes, liked: isLiked },
    (current, newState) => newState
  );

  async function handleLike() {
    const newLiked = !optimisticLikes.liked;
    const newCount = optimisticLikes.count + (newLiked ? 1 : -1);

    // Optimistically update UI
    setOptimisticLikes({ count: newCount, liked: newLiked });

    try {
      // Make API call
      const response = await fetch(`/api/posts/${postId}/like`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ liked: newLiked })
      });

      if (!response.ok) throw new Error('Failed to update');

      const result = await response.json();

      // Update actual state with server response
      setLikes(result.likes);
      setIsLiked(result.liked);
    } catch (error) {
      // On error, the optimistic state automatically reverts
      console.error('Like failed:', error);
    }
  }

  return (
    <button onClick={handleLike} className={optimisticLikes.liked ? 'liked' : ''}>
      {optimisticLikes.liked ? '❤️' : '🤍'} {optimisticLikes.count}
    </button>
  );
}

// Todo list with optimistic add/remove
function TodoList() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Learn React', completed: false },
    { id: 2, text: 'Build app', completed: false }
  ]);

  const [optimisticTodos, addOptimisticTodo] = useOptimistic(
    todos,
    (currentTodos, optimisticValue) => {
      if (optimisticValue.action === 'add') {
        return [...currentTodos, {
          ...optimisticValue.todo,
          pending: true
        }];
      }
      if (optimisticValue.action === 'remove') {
        return currentTodos.filter(t => t.id !== optimisticValue.id);
      }
      if (optimisticValue.action === 'toggle') {
        return currentTodos.map(t =>
          t.id === optimisticValue.id
            ? { ...t, completed: !t.completed, pending: true }
            : t
        );
      }
      return currentTodos;
    }
  );

  async function addTodo(text) {
    const tempId = Date.now();
    const newTodo = { id: tempId, text, completed: false };

    // Optimistic update
    addOptimisticTodo({ action: 'add', todo: newTodo });

    try {
      const response = await fetch('/api/todos', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text })
      });

      const savedTodo = await response.json();
      setTodos(current => [...current, savedTodo]);
    } catch (error) {
      console.error('Failed to add todo');
      // Optimistic update reverts automatically
    }
  }

  async function toggleTodo(id) {
    addOptimisticTodo({ action: 'toggle', id });

    try {
      await fetch(`/api/todos/${id}/toggle`, { method: 'PATCH' });
      setTodos(current =>
        current.map(t => t.id === id ? { ...t, completed: !t.completed } : t)
      );
    } catch (error) {
      console.error('Failed to toggle todo');
    }
  }

  return (
    <div>
      <form onSubmit={(e) => {
        e.preventDefault();
        const input = e.target.elements.todo;
        addTodo(input.value);
        input.value = '';
      }}>
        <input name="todo" placeholder="Add todo..." />
        <button type="submit">Add</button>
      </form>

      <ul>
        {optimisticTodos.map(todo => (
          <li
            key={todo.id}
            onClick={() => toggleTodo(todo.id)}
            style={{
              opacity: todo.pending ? 0.6 : 1,
              textDecoration: todo.completed ? 'line-through' : 'none'
            }}
          >
            {todo.text}
            {todo.pending && ' (saving...)'}
          </li>
        ))}
      </ul>
    </div>
  );
}
```

